return ['domain'=>NULL,'plural-forms'=>'nplurals=3; plural=((n==1) ? 0 : (n>=2 && n<=4) ? 1 : 2);','language'=>'sk_SK','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Aktualizujte doplnok TranslatePress - Multilingual na verziu %1$s alebo vyššiu, aby %2$s fungoval správne.','Please install and activate the TranslatePress - Multilingual plugin'=>'Nainštalujte a aktivujte doplnok TranslatePress - Multilingual','Install & Activate'=>'Nainštalovať & Aktivovať','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Aktualizujte TranslatePress - Multilingual na verziu %2$s alebo novšiu. Vaša aktuálne nainštalovaná verzia TranslatePress - Multilingual už nie je kompatibilná s aktuálnou verziou %1$s.','All TranslatePress functionalities are disabled until then.'=>'Všetky funkcie TranslatePress sú dovtedy zakázané.','Update Now'=>'Aktualizovať teraz','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Tento doplnok TranslatePress bol presunutý do hlavného doplnku a už sa nepoužíva. Môžete ho odstrániť.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> vyžaduje na spustenie aspoň PHP verziu 5.6.20+. Ide o <a href="%s">minimálnu požiadavku najnovšej verzie WordPress</a>. Kontaktujte správcu servera a požiadajte ho o aktualizáciu vašej verzie PHP.','Advanced'=>'Rozšírené','Settings saved.'=>'Nastavenia boli uložené.','Are you sure you want to remove this item?'=>'Naozaj chcete odstrániť túto položku?','Remove'=>'Odstrániť','Add'=>'Pridať','Select...'=>'Vybrať...','[%s] Low TranslatePress AI Words'=>'[%s] TranslatePress AI – dochádzajú slová','upgrade your plan or get extra AI Words'=>'inovovať plán alebo získať ďalšie AI slová','upgrade your plan'=>'inovovať plán','TranslatePress AI words are running low on your site.'=>'Na vašej stránke dochádzajú slová TranslatePress AI.','Current status: %s words remaining'=>'Aktuálny stav: počet zostávajúcich slov: %s','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Po vyčerpaní zostávajúcich AI slov sa pozastaví automatický preklad cez TranslatePress AI.','To continue translating your content, please %1$s over at %2$s'=>'Ak chcete pokračovať v preklade vášho obsahu, %1$s na %2$s','Manage Notification: %s'=>'Spravovať upozornenie: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Je dostupná nová verzia %1$s. %2$sZobraziť podrobnosti verzie %3$s%4$s alebo %5$saktualizovať teraz%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Je dostupná nová verzia %1$s. %2$sZobraziť podrobnosti verzie %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Ak chcete povoliť aktualizácie, %1$szadajte svoj licenčný kľúč%2$s. Potrebujete licenčný kľúč? %3$sKúpiť teraz%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Ak chcete povoliť aktualizácie, prejdite na %1$sstránku licencie%2$s a skontrolujte, či máte platnú licenciu.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Ak chcete povoliť aktualizácie, vaša licencia sa musí obnoviť. Prejdite na stránku %1$sTranslatePress Account%2$s a prihláste sa, aby ste ju obnovili.','You do not have permission to install plugin updates'=>'Nemáte oprávnenie na inštaláciu aktualizácií zásuvného modulu','Error'=>'Chyba','Your TranslatePress license key is invalid or missing.'=>'Váš licenčný kľúč TranslatePress je neplatný alebo chýba.','Your license key expired on %s.'=>'Váš licenčný kľúč vypršal %s.','Your license key has been disabled.'=>'Váš licenčný kľúč bol deaktivovaný.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Váš licenčný kľúč je deaktivovaný pre túto URL. Znova ho aktivujte na stránke <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Správa stránok.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Nezhoda licenčného kľúča.</strong> Zadaný licenčný kľúč nezodpovedá nainštalovanej verzii TranslatePress.</p><p>Skontrolujte, či ste nainštalovali správnu verziu pre svoju licenciu z vášho TranslatePress Account.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Ak máte nainštalovaný iba bezplatný zásuvný modul, ale pridali ste platenú licenciu, nainštalujte platený zásuvný modul z vášho TranslatePress Account.','Your license key has reached its activation limit.'=>'Váš licenčný kľúč dosiahol limit aktivácií.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Inovujte svoj plán na pridanie ďalších stránok. %1$sInovovať teraz%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Táto webová stránka je už aktivovaná pod bezplatnou licenciou. Každá webová stránka môže používať iba jednu bezplatnú licenciu.','An error occurred, please try again.'=>'Vyskytla sa chyba, skúste to znova.','You have successfully activated your license'=>'Vaša licencia bola úspešne aktivovaná.','Others'=>'Ostatné','Restrict by Language'=>'Obmedziť podľa jazyka','Exclude from Language'=>'Vylúčiť z jazyka','Restrict element to language'=>'Obmedziť prvok na jazyk','Show this element only in one language.'=>'Zobraziť tento prvok iba v jednom jazyku.','Enable translation'=>'Povoliť preklad','Allow translation to the corresponding language only if the content is written in the default language.'=>'Povoliť preklad do príslušného jazyka iba ak je obsah napísaný v predvolenom jazyku.','Select language'=>'Vybrať jazyk','Choose in which language to show this element.'=>'Vyberte, v ktorom jazyku sa má zobraziť tento prvok.','Exclude element from language'=>'Vylúčiť prvok z jazyka','Exclude this element from specific languages.'=>'Vylúčiť tento prvok z konkrétnych jazykov.','Select languages'=>'Vybrať jazyky','Choose from which languages to exclude this element.'=>'Vyberte, z ktorých jazykov sa má tento prvok vylúčiť.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Tento prvok bude stále viditeľný, keď budete prekladať svoj web prostredníctvom editora prekladov.','The content of this element should be written in the default language.'=>'Obsah tohto prvku by mal byť napísaný v predvolenom jazyku.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> zaznamenal SQL chyby. <a href="%s" title="View TranslatePress SQL Errors">Pozrite si chyby</a>.','Automatic translation has been disabled.'=>'Automatický preklad bol zakázaný.','Dismiss this notice.'=>'Zatvoriť toto upozornenie.','Logged errors'=>'Zaznamenané chyby','These are the most recent 5 errors logged by TranslatePress:'=>'Toto je 5 najnovších chýb, ktoré zaznamenal TranslatePress:','Yes'=>'Áno','Why are these errors occuring'=>'Prečo dochádza k týmto chybám','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Ak TranslatePress pri vykonávaní dotazov vo vašej databáze zistí nejaký problém, môže zakázať funkciu automatického prekladu, aby sa predišlo akýmkoľvek dodatočným poplatkom od Google/DeepL. Funkciu automatického prekladu je potrebné zapnúť manuálne až po vyriešení problémov.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Zistené SQL chyby môžu nastať z rôznych dôvodov vrátane chýbajúcich tabuliek, chýbajúcich oprávnení pre SQL používateľa na vytváranie tabuliek alebo vykonávanie iných operácií, problémov po migrácii stránky alebo zmien v konfigurácii SQL servera.','What you can do in this situation'=>'Čo môžete v tejto situácii urobiť','Plan A.'=>'Plán A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Prejdite na Nastavenia -> TranslatePress -> záložka Všeobecné a uložte nastavenia. Tým sa znova vygenerujú tabuľky pomocou vašich aktuálnych SQL nastavení. Skontrolujte, či pri prezeraní vašej webstránky v preloženom jazyku nenastávajú žiadne ďalšie chyby. Pozrite sa na časové značky chýb, aby ste sa uistili, že nevidíte staré chyby. Zobrazuje sa len najnovších 5 chýb.','Plan B.'=>'Plán B.','If your problem isn\'t solved, try the following steps:'=>'Ak váš problém nie je vyriešený, vyskúšajte nasledujúce kroky:','Create a backup of your database'=>'Vytvorte zálohu vašej databázy','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Vytvorte kópiu každej prekladovej tabuľky, v ktorej narážate na chyby. Tabuľku môžete skopírovať v rámci tej istej databázy (napríklad trp_dictionary_en_us_es_es_COPY) – tento krok vykonajte len vtedy, ak chcete zachovať aktuálne preklady','Remove the trouble tables by executing the DROP function on them'=>'Odstráňte problematické tabuľky vykonaním funkcie DROP na nich','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Prejdite na Nastavenia -> TranslatePress -> záložka Všeobecné a uložte nastavenia. Tým sa znova vygenerujú tabuľky pomocou vášho aktuálneho SQL servera.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Skopírujte príslušný obsah z duplikovaných tabuliek (napríklad trp_dictionary_en_us_es_es_COPY) do novo vygenerovanej tabuľky (trp_dictionary_en_us_es_es) – tento krok vykonajte len vtedy, ak chcete zachovať aktuálne preklady','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Otestujte, či všetko funguje. Ak niečo zlyhalo, môžete obnoviť zálohu, ktorú ste vytvorili v prvom kroku. Skontrolujte, či pri prezeraní vašej webstránky v preloženom jazyku nenastávajú žiadne ďalšie chyby. Pozrite sa na časové značky chýb, aby ste sa uistili, že nevidíte staré chyby. Zobrazuje sa len najnovších 5 chýb.','Plan C.'=>'Plán C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Ak váš problém stále nie je vyriešený, skúste sa opýtať svojho poskytovateľa hostingu na tieto chyby. Najčastejším problémom sú chýbajúce oprávnenia pre SQL používateľa, napríklad oprávnenie Create Tables.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Nepodarilo sa nainštalovať. Skúste to znova z <a href="%s" >Panelu doplnkov.</a>','Active'=>'Aktívny','Permission denied.'=>'Prístup zamietnutý.','Invalid nonce.'=>'Neplatný nonce.','Settings scope unknown.'=>'Neznámy rozsah nastavení.','Legacy disabled.'=>'Zastaralý režim je zakázaný.','Language Switcher'=>'Prepínač jazykov','Change language to %s'=>'Zmeniť jazyk na %s','Automatic Translation'=>'Automatický preklad','DeepL'=>'DeepL','Unsupported languages'=>'Nepodporované jazyky','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Vybraný nástroj automatického prekladu nepodporuje tieto jazyky.<br>Stránky v týchto jazykoch môžete stále preložiť manuálne pomocou Prekladateľského editora.','API key validation failed.'=>'Overenie API kľúča zlyhalo.','API key verification was successful.'=>'Overenie API kľúča bolo úspešné.','Please enter your Google Translate key.'=>'Zadajte svoj kľúč Google Translate.','Please enter your DeepL API key.'=>'Zadajte svoj DeepL API kľúč.','Not TranslatePress onboarding page.'=>'Toto nie je stránka úvodného nastavenia TranslatePress.','Step %s does not exist'=>'Krok %s neexistuje','Welcome'=>'Vitajte','Add Languages'=>'Pridať jazyky','Enable Addons'=>'Povoliť doplnky','Finalize'=>'Dokončiť','Exit Setup'=>'Ukončiť nastavenie','Upgrade'=>'Inovovať','Nothing here'=>'Nič tu nie je','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Vaša licencia <strong>TranslatePress</strong> chýba alebo je neplatná. <br/>Prosím, %1$szaregistrujte svoju kópiu%2$s, aby ste povolili automatický preklad webu cez TranslatePress AI, prémiové doplnky, automatické aktualizácie a podporu. Potrebujete licenčný kľúč? %3$sKúpte si ho teraz%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Vaša licencia <strong>TranslatePress</strong> vyprší %1$s. Prosím, %2$sobnovte svoju licenciu%3$s, aby ste naďalej mali prístup k automatickým prekladom cez TP AI, prémiovým doplnkom, sťahovaniu produktov a automatickým aktualizáciám. %4$sObnoviť teraz%5$s','Error: '=>'Chyba: ','Something went wrong, please try again.'=>'Vyskytla sa chyba, skúste to znova.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Vaša licencia <strong>TranslatePress</strong> vypršala. <br/>Prosím, %1$sobnovte svoju licenciu%2$s, aby ste naďalej mali prístup k automatickým prekladom cez TranslatePress AI, prémiovým doplnkom, sťahovaniu produktov a automatickým aktualizáciám. %3$sObnoviť teraz %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Nezhoda licenčného kľúča. Zadaná licencia nezodpovedá nainštalovanej verzii <strong>%1$s</strong>. <br/>Skontrolujte, či ste pre svoju licenciu nainštalovali správnu verziu z %2$svášho TranslatePress Account%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Ak máte nainštalovaný iba bezplatný doplnok, ale pridali ste platenú licenciu, nainštalujte si platený doplnok z vášho TranslatePress Account.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Dosiahli ste limit aktivácií pre svoju licenciu <strong>%1$s</strong>. <br/>Spravujte svoje aktívne stránky z %2$svášho účtu%3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Vaša licencia je pre túto URL deaktivovaná. Znova ju aktivujte na <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Správa stránok.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Automatický preklad %1$s vyžaduje aktívnu licenciu. Prosím, %2$sobnovte%3$s svoju licenciu alebo si kúpte novú %4$stu%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Prosím, %1$szadajte%2$s svoj licenčný kľúč, aby ste povolili automatický preklad %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Zostáva vám menej ako 5 000 slov TranslatePress AI. Ak chcete pokračovať v automatickom preklade svojej webstránky, %skúpte si dodatočné AI slová so zľavou zo svojho účtu%s.',' Error: '=>' Chyba: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Táto webstránka je už aktivovaná pod bezplatnou licenciou. Každá webstránka môže používať iba jednu bezplatnú licenciu. Ak chcete získať viac slov TranslatePress AI, prejdite na prémiový plán z %1$svášho účtu%2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Nemáte platnú licenciu pre <strong>TranslatePress</strong>. %1$sZískajte ju zadarmo%2$s a získajte prístup k TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NOVÉ:</strong> Doplnok <strong>Different Domain per Language</strong> je tu! Posilnite svoje globálne SEO a vytvorte lokálny zážitok s doménami špecifickými pre krajinu, ako sú .de alebo .fr. Prejdite na <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business alebo Developer</a> a získajte k nemu prístup + ďalšie prémiové výhody!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NOVÉ:</strong> Doplnok <strong>Different Domain per Language</strong> je tu! Posilnite svoje globálne SEO a vytvorte lokálny zážitok s doménami špecifickými pre krajinu, ako sú .de alebo .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Zistite viac</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Denný limit znakov pre strojový preklad bol prekročený. Pre viac informácií skontrolujte stránku <strong>TranslatePress -> <a href="%s">Automatický preklad</a></strong>.','Marketing optin'=>'Marketingový opt-in','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Súhlaste s prijímaním oznámení o bezpečnostných a funkčných aktualizáciách a diagnostickým sledovaním bez citlivých údajov.','TranslatePress Preferred User Language'=>'Preferovaný jazyk používateľa TranslatePress','Preferred language to navigate the site'=>'Preferovaný jazyk na prehliadanie stránky','The language is automatically set based by the last visited language by the user.'=>'Jazyk sa automaticky nastavuje na základe posledného navštíveného jazyka používateľa.','Always use this language'=>'Vždy používať tento jazyk','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Zaškrtnutím tohto nastavenia zostane preferovaný jazyk nastavený na vyššie vybraný bez možnosti zmeny vo frontende.<br>Tento jazyk sa použije pri rôznych operáciách, napríklad pri odosielaní e-mailu používateľovi.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Ahoj! Zdá sa, že už nejaký čas používaš <strong>TranslatePress</strong> na preklad svojej webstránky. To je skvelé! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Ak si nájdeš pár chvíľ na jeho ohodnotenie na WordPress.org, veľmi by nám to pomohlo (a povzbudilo by ma to).','~ Razvan, developer of TranslatePress'=>'~ Razvan, vývojár TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Ohodnotiť TranslatePress na stránke pluginu WordPress.org','Ok, I will gladly help!'=>'OK, rád pomôžem!','No, thanks.'=>'Nie, ďakujem.','Full Language Names'=>'Plné názvy jazykov','Short Language Names'=>'Skrátené názvy jazykov','Flags with Full Language Names'=>'Vlajky s plnými názvami jazykov','Flags with Short Language Names'=>'Vlajky so skrátenými názvami jazykov','Only Flags'=>'Len vlajky','Full Language Names No HTML'=>'Plné názvy jazykov bez HTML','Bottom Right'=>'Vpravo dole','Bottom Left'=>'Vľavo dole','Top Right'=>'Vpravo hore','Top Left'=>'Vľavo hore','Dark'=>'Tmavý','Light'=>'Svetlý','Deactivate'=>'Deaktivovať','Activate'=>'Aktivovať','Invalid language code. Please try again.'=>'Neplatný kód jazyka. Skúste to znova.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Kódy jazykov môžu obsahovať iba znaky A-Z a-z 0-9 - _. Skontrolujte svoje kódy jazyka vo všeobecných nastaveniach TranslatePress.','Error! Duplicate URL slug values.'=>'Chyba! Duplicitné hodnoty URL slug.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Nemôžete vybrať dva jazyky, ktoré majú rovnaký <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">ISO kód</a>, ale odlišné formality, pretože by to viedlo k duplicitným <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang značkám</a>.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Bol zistený duplicitný jazyk.<br>Každý jazyk možno pridať iba raz, aby sa zaistila presná správa prekladov.<br> Zmeňte duplicitný záznam jazyka a skúste to znova. ','Current Language'=>'Aktuálny jazyk','Opposite Language'=>'Opačný jazyk','General'=>'Všeobecné','Translate Site'=>'Preložiť stránku','Addons'=>'Doplnky','License'=>'Licencia','Settings'=>'Nastavenia','Activate License'=>'Aktivovať licenciu','Pro Features'=>'Pro funkcie','Need Help?'=>'Potrebujete pomoc?','Recent community discussions'=>'Nedávne komunitné diskusie','Loading...'=>'Načítava sa...','Unable to load forum posts'=>'Nepodarilo sa načítať príspevky fóra','Ask a Question'=>'Položiť otázku','View All Topics'=>'Zobraziť všetky témy','by'=>'od','Have a question?'=>'Máte otázku?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Získajte pomoc priamo od vývojárov pluginu, navrhnite vylepšenia alebo zdieľajte svoju spätnú väzbu!','Tip for faster help:'=>'Tip na rýchlejšiu pomoc:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Uveďte, čo ste skúsili, čo ste očakávali a čo sa stalo. Snímky obrazovky pomáhajú!','Toggle support chat'=>'Prepnúť chat podpory','Ask the community'=>'Opýtať sa komunity','Close'=>'Zavrieť','Empty feed response'=>'Prázdna odpoveď kanála','Unable to parse feed'=>'Nepodarilo sa spracovať kanál','Just now'=>'Práve teraz','%d hour ago'=>'pred %d hodinou' . "\0" . 'pred %d hodinami' . "\0" . 'pred %d hodinami','%d day ago'=>'pred %d dňom' . "\0" . 'pred %d dňami' . "\0" . 'pred %d dňami','Source'=>'Zdroj','Srcset'=>'Srcset','Alt attribute'=>'Atribút alt','Title attribute'=>'Atribút title','Anchor link'=>'Odkaz na kotvu','Placeholder attribute'=>'Atribút placeholder','Submit attribute'=>'Atribút submit','Text'=>'Text','Video Poster'=>'Náhľad videa','plural form'=>'Množné číslo','one'=>'Jednotné číslo','few'=>'Niekoľko','many'=>'Mnoho','other'=>'Iné','Saved'=>'Uložené','Save'=>'Uložiť','Saving translation...'=>'Ukladá sa preklad...','You have unsaved changes!'=>'Máte neuložené zmeny!','Discard changes'=>'Zahodiť zmeny','Discard All'=>'Zahodiť všetko','Loading Strings...'=>'Načítavanie reťazcov...','Select string to translate...'=>'Vyberte reťazec na preklad...','Close Editor'=>'Zavrieť editor','From'=>'Z','To'=>'Do','Add Media'=>'Pridať médium','Other languages'=>'Ostatné jazyky','Context'=>'Kontext','View Website As'=>'Zobraziť webstránku ako','Available in our Pro Versions'=>'Dostupné v našich Pro verziách','Select or Upload Media'=>'Vyberte alebo nahrajte médium','Use this media'=>'Použiť toto médium','Translate'=>'Preložiť','Translate entire block element'=>'Preložiť celý blokový prvok','Split block to translate strings individually'=>'Rozdeliť blok na preklad jednotlivých reťazcov','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Uložiť zmeny v preklade. Skratka: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Prejsť na ďalší reťazec v rozbaľovacom zozname. Skratka: CTRL(⌘) + ALT + pravá šípka','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Prejsť na predchádzajúci reťazec v rozbaľovacom zozname. Skratka: CTRL(⌘) + ALT + ľavá šípka','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Zahodiť všetky zmeny. Skratka: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Zahodiť zmeny v tomto textovom poli. Ak chcete zahodiť zmeny vo všetkých textových poliach, použite skratku: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Zavrieť tooltip','Quick Intro'=>'Rýchly úvod','Are you sure you want to split this phrase into smaller parts?'=>'Naozaj chcete rozdeliť túto frázu na menšie časti?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Tento reťazec ešte nie je pripravený na preklad.<br>Skúste to znova o chvíľu...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'Aby táto možnosť fungovala, aktualizujte prosím doplnok Browse as other role na najnovšiu verziu.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'Na preklad slugov aktualizujte doplnok SEO Pack na najnovšiu verziu.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Nový jazyk môžete pridať v <a href="%s">Nastavenia->TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Stále však môžete pomocou TranslatePress <strong style="background: #f5fb9d;">upravovať gettext reťazce</strong> dostupné na vašej stránke.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Reťazce vytvorené používateľom nemožno upravovať, iba tie z tém a doplnkov.','Extra Translation Features'=>'Dodatočné funkcie prekladu','Support for 130+ Extra Languages'=>'Podpora 130+ dodatočných jazykov','Access to TranslatePress AI'=>'Prístup k TranslatePress AI','Translate SEO Title, Description, Slug'=>'Preložiť SEO titulok, popis, slug','Publish only when translation is complete'=>'Publikovať iba po dokončení prekladu','Translate by Browsing as User Role'=>'Prekladať pri prehliadaní v inej používateľskej roli','Different Menu Items for each Language'=>'Rozličné položky menu pre každý jazyk','Automatic User Language Detection'=>'Automatická detekcia jazyka používateľa','Upgrade to PRO'=>'Upgrade na PRO','Upgrade to PRO with our biggest discount of the year!'=>'Upgrade na PRO s našou najväčšou zľavou roka!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Tento Black Friday získajte prístup k týmto funkciám a ďalším za zlomok ceny:','No available suggestions'=>'Žiadne dostupné návrhy','Suggestions from translation memory'=>'Návrhy z prekladovej pamäte','Click to Copy'=>'Kliknutím skopírujete','Human Translation'=>'Ľudský preklad','Machine Translation'=>'Strojový preklad','Text on this page is %s% translated into all languages.'=>'Text na tejto stránke je na %s% preložený do všetkých jazykov.','%1$s% of text on this page is translated into %2$s.'=>'%1$s% textu na tejto stránke je preložené do jazyka %2$s.','This page is %1$s% translated into %2$s.'=>'Táto stránka je na %1$s% preložená do jazyka %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'Slug, ktorý sa pokúšate upraviť, sa nachádza aj v iných typoch slugov: %s. Jeho úpravou sa nahradí každý výskyt bez ohľadu na aktuálny typ.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Umiestnite kurzor na ľubovoľný text na stránke, kliknite na %s,<br> a potom upravte preklad v bočnom paneli.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'Nezabudnite uložiť preklad. Použite klávesovú skratku CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Prepnite jazyk, aby ste videli zmeny prekladu priamo na stránke.','Search for any text in this page in the dropdown.'=>'Vyhľadajte ľubovoľný text na tejto stránke v rozbaľovacej ponuke.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Vaša %s licencia <span class="trp-license-status-emphasized">vypršala</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Obnovte svoju licenciu, aby ste naďalej mali prístup k TranslatePress AI, prémiovým rozšíreniam, automatickým aktualizáciám a podpore.','Renew Now'=>'Obnoviť teraz','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Tento Black Friday obnovte svoju licenciu za špeciálnu cenu</strong>, aby ste naďalej mali prístup k produktom na stiahnutie, automatickým aktualizáciám a podpore.','Get Deal'=>'Využiť ponuku','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Vaša %s licencia bola <span class="trp-license-status-emphasized">vrátená</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Zakúpte si novú licenciu, aby ste naďalej mali prístup k TranslatePress AI, prémiovým rozšíreniam, automatickým aktualizáciám a podpore.','Purchase a new license'=>'Zakúpiť novú licenciu','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Vaša licencia %s je <span class="trp-license-status-emphasized">chýbajúca alebo neplatná</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Zadajte platnú licenciu, aby ste získali prístup k TranslatePress AI, prémiovým doplnkom, automatickým aktualizáciám a podpore. Potrebujete licenčný kľúč? %1$sZakúpiť teraz%2$s','Enter a valid license'=>'Zadať platnú licenciu','Slugs'=>'Slugy','Meta Information'=>'Meta informácie','String List'=>'Zoznam reťazcov','Gettext Strings'=>'Gettext reťazce','Images'=>'Obrázky','Videos'=>'Videá','Audios'=>'Audio','Dynamically Added Strings'=>'Dynamicky pridané reťazce','Translation Editor'=>'Editor prekladov','Edit translations by visually selecting them on each site page'=>'Upravovať preklady vizuálnym výberom na každej stránke webu','String Translation'=>'Preklad reťazcov','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'Upraviť preklady URL slugov, doplnkov a tém (e-maily, formuláre atď.)','Current User'=>'Aktuálny používateľ','Logged Out'=>'Odhlásený','Translate Page'=>'Preložiť stránku','Add a New Language'=>'Pridať nový jazyk','Get a Free AI License'=>'Získajte bezplatnú AI licenciu','Your License is Invalid'=>'Vaša licencia je neplatná','Get More AI Words (%d left)'=>'Získajte viac AI slov (zostáva %d)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Otvorí príspevok v editore prekladu. Príspevok musí byť vopred uložený ako koncept alebo zverejnený.','Security check'=>'Bezpečnostná kontrola','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Upozornenie:</strong> Niektoré reťazce môžu obsahovať nesprávne zakódované znaky. To môže viesť k porušeniu dotazov, v dôsledku čoho sa stránka zobrazí nepreložená naživo. Zvážte úpravu nasledujúcich reťazcov alebo ich spôsobu výstupu.','TranslatePress data update'=>'Aktualizácia údajov TranslatePress','We need to update your translations database to the latest version.'=>'Musíme aktualizovať vašu databázu prekladov na najnovšiu verziu.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'Aktualizácia umožní upravovať preklady lokalizovaného textu z doplnkov a tém. Existujúci preklad bude naďalej fungovať podľa očakávania.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'DÔLEŽITÉ: Dôrazne sa odporúča najskôr zálohovať databázu!\\nSte si istí, že chcete pokračovať?','Run the updater'=>'Spustiť aktualizátor','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'Aktualizácia umožní úpravu prekladov slugov. Existujúci preklad bude naďalej fungovať podľa očakávania.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Prosím, aktivujte SEO doplnok v časti<br/>WordPress -> Nastavenia -> TranslatePress -> Doplnky','Go to Addons'=>'Prejsť na Doplnky','The SEO Pack add-on allows translation of all the URL slugs:'=>'Doplnok SEO Pack umožňuje preklad všetkých URL slugov:','Taxonomy slugs'=>'Slugy taxonómií','Term slugs'=>'Slugy výrazov','Post slugs (this includes pages and custom post types)'=>'Slugy príspevkov (zahŕňa stránky a vlastné typy príspevkov)','Post type base slugs'=>'Základné slugy typov príspevkov','WooCommerce slugs'=>'Slugy WooCommerce','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'Doplnok SEO Pack je dostupný so VŠETKÝMI prémiovými verziami pluginu.','Upgrade to Pro'=>'Inovovať na Pro','Description'=>'Popis','Article Section'=>'Sekcia článku','Article Tag'=>'Značka článku','OG Title'=>'OG názov','OG Site Name'=>'OG názov stránky','OG Description'=>'OG popis','OG Image Alt'=>'OG alternatívny text obrázka','Twitter Title'=>'Názov pre Twitter','Twitter Description'=>'Popis pre Twitter','Twitter Image Alt'=>'Alternatívny text obrázka pre Twitter','Page Title'=>'Názov stránky','Dublin Core Title'=>'Názov Dublin Core','Dublin Core Description'=>'Popis Dublin Core','OG Image'=>'OG obrázok','OG Image Secure URL'=>'OG zabezpečená URL obrázka','Twitter Image'=>'Obrázok pre Twitter','Removing cdata dictionary strings for language %s...'=>'Odstraňujú sa reťazce slovníka CDATA pre jazyk %s...','Removing untranslated dictionary links for language %s...'=>'Odstraňovanie nepreložených odkazov slovníka pre jazyk %s...','Removing duplicated gettext strings for language %s...'=>'Odstraňujú sa duplicitné reťazce gettext pre jazyk %s...','Removing duplicated dictionary strings for language %s...'=>'Odstraňujú sa duplicitné reťazce slovníka pre jazyk %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'Odstraňujú sa nepreložené reťazce slovníka, pre ktoré je dostupný preklad pre jazyk %s...','Inserting original strings for language %s...'=>'Vkladajú sa pôvodné reťazce pre jazyk %s...','Cleaning original strings table for language %s...'=>'Čistí sa tabuľka pôvodných reťazcov pre jazyk %s...','Updating original string ids for language %s...'=>'Aktualizujú sa ID pôvodných reťazcov pre jazyk %s...','Regenerating original meta table for language %s...'=>'Regenerovanie tabuľky meta údajov pôvodných reťazcov pre jazyk %s...','Cleaning original meta table for language %s...'=>'Čistenie tabuľky meta údajov pôvodných reťazcov pre jazyk %s...','Replacing original id NULL with value for language %s...'=>'Nahradzovanie hodnoty NULL ID pôvodného reťazca hodnotou pre jazyk %s...','Inserting gettext original strings for language %s...'=>'Vkladajú sa pôvodné reťazce gettext pre jazyk %s...','Cleaning gettext original strings table for language %s...'=>'Čistí sa tabuľka pôvodných reťazcov gettext pre jazyk %s...','Updating gettext original string ids for language %s...'=>'Aktualizujú sa ID pôvodných reťazcov gettext pre jazyk %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'Migrujú sa slugy taxonómií a základné slugy typov príspevkov do novej štruktúry tabuľky...','Migrating post slugs to new table structure for language %s...'=>'Migrujú sa slugy príspevkov do novej štruktúry tabuľky pre jazyk %s...','Migrating term slugs to new table structure for language %s...'=>'Prebieha migrácia slugov výrazov do novej štruktúry tabuľky pre jazyk %s...','Finishing up...'=>'Dokončovanie...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'Optimalizácia databázy sa nepodarila dokončiť. Odporúčame obnoviť pôvodnú databázu alebo <a href="%s">skúsiť to znova.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'Aktualizácia bola prerušená! Váš užívateľský účet nemá oprávnenie vykonávať aktualizácie databázy.','Update aborted! Invalid nonce.'=>'Aktualizácia bola prerušená! Neplatný nonce.','Update aborted! Incorrect action.'=>'Aktualizácia bola prerušená! Nesprávna akcia.','Update aborted! Incorrect language code.'=>'Aktualizácia prerušená! Nesprávny kód jazyka.','Updating database to version %s+'=>'Aktualizácia databázy na verziu %s+','Processing table for language %s...'=>'Spracovávanie tabuľky pre jazyk %s...','Back to TranslatePress Settings'=>'Späť do nastavení TranslatePress','Successfully updated database!'=>'Databáza bola úspešne aktualizovaná!',' done.'=>' hotové.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Všetky individuálne doplnky TranslatePress <a href="%1$s" target="_blank">boli zrušené</a> a sú teraz zahrnuté v prémiových verziách TranslatePress Personal, Business a Developer. Prihláste sa na svoju <a href="%2$s" target="_blank">stránku účtu</a>, stiahnite si novú prémiovú verziu a nainštalujte ju. Vaše individuálne nastavenia doplnkov budú prenesené.','Brand-new Language Switcher Settings are here!'=>'Úplne nové nastavenia prepínača jazykov sú tu!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Preskúmajte predpripravené šablóny, farby prepínača, štýly vlajok, medzery, rozloženia a ďalšie. Pomocou živého náhľadu si doladíte prepínač za pár sekúnd.','Start customizing'=>'Začnite prispôsobovať','Read documentation'=>'Prečítajte si dokumentáciu','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> vyžaduje <strong><a href="http://php.net/manual/en/book.mbstring.php">knižnicu PHP Multibyte String</a></strong>. Kontaktujte správcu servera, aby vám ju nainštaloval.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'Na hostingu WPEngine bolo zistené obmedzenie dlhých dotazov. Niektoré veľké stránky sa môžu zobraziť nepreložené. Toto obmedzenie môžete odstrániť pridaním nasledujúceho do súboru wp-config.php vášho webu: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Vlastná vlajka jazyka','The Language code of the added custom language cannot be empty.'=>'Kód jazyka pridaného vlastného jazyka nemôže byť prázdny.','The Language code of the added custom language is invalid.'=>'Kód jazyka pridaného vlastného jazyka je neplatný.','The Automatic Translation Code of the added custom language is invalid.'=>'Automatický prekladový kód pridaného vlastného jazyka je neplatný.','TranslatePress Add-ons'=>'Doplnky TranslatePress','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Najskôr si musíte zakúpiť túto verziu, aby ste mali prístup k doplnku %1$stu%2$s.','Please %1$senter your license%2$s key first, to activate this addon.'=>'Najprv %1$szadajte svoj licenčný%2$s kľúč, aby ste aktivovali tento doplnok.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Na prístup k doplnku potrebujete aktívnu licenciu. Obnovte ju alebo si zakúpte novú %1$stu%2$s.','Advanced Add-ons'=>'Rozšírené doplnky','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Tieto doplnky rozširujú váš prekladový plugin a sú dostupné v plánoch Developer, Business a Personal.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (zastaralé)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'Podpora SEO pre slug stránky, názov stránky, popis a informácie sociálneho grafu Facebooku a Twitteru. Atribút HTML lang je správne nastavený.','Multiple Languages'=>'Viacero jazykov','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Pridajte toľko jazykov, koľko potrebujete, aby bol váš projekt globálny. Jazyk zverejnite až vtedy, keď budú všetky preklady hotové.','Pro Add-ons'=>'Pro doplnky','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Tieto doplnky rozširujú váš prekladový plugin a sú dostupné v plánoch Business a Developer.','DeepL Automatic Translation'=>'Automatický preklad DeepL','Automatically translate your website through the DeepL API.'=>'Automaticky preložte svoju webstránku prostredníctvom DeepL API.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Vyzve návštevníkov, aby prepli na preferovaný jazyk na základe nastavenia prehliadača alebo IP adresy, a zapamätá si naposledy navštívený jazyk.','Translator Accounts'=>'Účty prekladateľov','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Vytvorte prekladateľské účty pre nových používateľov alebo umožnite existujúcim používateľom, ktorí nie sú administrátori, prekladať vašu webstránku.','Browse As User Role'=>'Prehliadať ako používateľská rola','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Prehliadajte svoju webstránku tak, ako by to robila konkrétna používateľská rola. Veľmi užitočné pre dynamický obsah alebo skrytý obsah, ktorý sa zobrazuje konkrétnym používateľom.','Navigation Based on Language'=>'Navigácia na základe jazyka','Configure different menu items for different languages.'=>'Nastavte rôzne položky menu pre rôzne jazyky.','Different Domain per Language'=>'Iná doména pre každý jazyk','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Pripojte k jednotlivým preloženým verziám samostatné domény alebo subdomény. Posilnite lokálnu identitu svojej značky a zlepšite SEO výkon pre každý podporovaný jazyk.','Recommended Plugins'=>'Odporúčané pluginy','A short list of plugins you can use to extend your website.'=>'Krátky zoznam pluginov, ktorými môžete rozšíriť svoju webstránku.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Zachyťte vo registračnom formulári viac informácií o používateľoch pomocou vlastných polí používateľského profilu z Profile Builder a/alebo pridajte proces potvrdenia e-mailom na overenie účtov vašich zákazníkov.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Prijímajte platby používateľov, vytvárajte plány predplatného a obmedzujte obsah na vašom členskom webe.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Vytvárajte automatizácie a pracovné postupy bez kódu na vašom webe WordPress. Jednoducho prepojte svoje pluginy, weby a aplikácie.','Save Changes'=>'Uložiť zmeny','TranslatePress Errors'=>'Chyby TranslatePress','There are no logged errors.'=>'Nie sú žiadne zaznamenané chyby.','Change language'=>'Zmeniť jazyk','Website language selector'=>'Výber jazyka webstránky','WordPress Translation Plugin'=>'Prekladový plugin pre WordPress','Available languages'=>'Dostupné jazyky','Language Switcher update notice'=>'Upozornenie na aktualizáciu prepínača jazyka','Legacy language switcher is currently enabled'=>'Starý prepínač jazyka je momentálne povolený','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Prepínač sme vylepšili pre bohatšie prispôsobenie a lepšiu používateľskú skúsenosť.<br>Na používanie nového konfigurátora vypnite <strong>Načítať starý prepínač jazyka</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Poznámka: Kedykoľvek sa môžete vrátiť späť z <strong>Rozšírených nastavení → <a href="%s">Riešenie problémov</a></strong>.','Enable the new switcher'=>'Povoliť nový prepínač','Your License Key is valid.'=>'Váš licenčný kľúč je platný.','Your License Key is invalid.'=>'Váš licenčný kľúč je neplatný.','Your License has expired.'=>'Vaša licencia vypršala.','Deactivate License'=>'Deaktivovať licenciu','Add a license key'=>'Pridať licenčný kľúč','License Key'=>'Licenčný kľúč','Manage your license in your %1$s.'=>'Spravujte svoju licenciu v %1$s.','Account Page'=>'Stránka účtu','Don’t have a TranslatePress AI License Key?'=>'Nemáte licenčný kľúč TranslatePress AI?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Môžete ho získať %1$szadarmo%2$s vytvorením bezplatného účtu. Zahŕňa to:','Access to TranslatePress AI for instant automatic translations'=>'Prístup k TranslatePress AI pre okamžité automatické preklady','2000 AI words to translate automatically'=>'2000 AI slov na automatický preklad','Get a free License Today'=>'Získajte dnes bezplatnú licenciu','Debug Information'=>'Informácie o ladení','Debug Data for License Checking'=>'Ladiace údaje pre kontrolu licencie','Debug Data for License Activation'=>'Ladiace údaje pre aktiváciu licencie','Get more AI words and unlock all features with TranslatePress Pro.'=>'Získajte viac AI slov a odomknite všetky funkcie s TranslatePress Pro.','Upgrade now ↗'=>'Upgradnúť teraz ↗','Already purchased a Premium version?'=>'Už ste si zakúpili prémiovú verziu?','Go to your %1$s'=>'Prejdite na svoj %1$s','TranslatePress.com Account'=>'Účet TranslatePress.com','Download & Install the Pro plugin'=>'Stiahnite a nainštalujte doplnok Pro','Learn More'=>'Ďalšie informácie','Get a translation volume estimate with a detailed breakdown per page'=>'Získajte odhad objemu prekladu s podrobným rozčlenením podľa stránok','Find how many translatable words are on your website'=>'Zistite, koľko preložiteľných slov sa nachádza na vašom webe','Enable Automatic Translation'=>'Povoliť automatický preklad','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'Ak chcete používať <strong>DeepL</strong> na automatický preklad, aktivujte tento doplnok Pro v <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'Automatický preklad cez <strong>DeepL</strong> je dostupný ako <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'Inováciou získate prístup ku všetkým plateným doplnkom, prémiovej podpore a pomôžete financovať budúci vývoj TranslatePress.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Upozorňujeme, že používanie rozhrania DeepL API sa platí osobitne. Pozrite si <a href="https://www.deepl.com/pro.html#developer">informácie o cenách DeepL</a>.','TranslatePress Pro Add-ons'=>'Doplnky TranslatePress Pro','Test API credentials'=>'Otestovať prihlasovacie údaje API','Check if the selected translation engine is configured correctly.'=>'Skontrolujte, či je vybraný prekladový engine nakonfigurovaný správne.','Alternative Engines'=>'Alternatívne enginy','Switch to TranslatePress AI'=>'Prepnúť na TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'Integrovať strojový preklad priamo do vašej webstránky WordPress.','More info'=>'Viac informácií','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Vyberte, ktorý engine chcete použiť s cieľom %1$s automaticky preložiť vašu webstránku.','Automatic Translation Settings'=>'Nastavenia automatického prekladu','AI Words Low Notification'=>'Upozornenie na nízky počet AI slov','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Dostanete e-mailové upozornenie, keď počet slov TranslatePress AI klesne pod zadanú hranicu.','This feature is only available when using the TranslatePress AI translation engine.'=>'Táto funkcia je dostupná len pri používaní prekladového enginu TranslatePress AI.','Notification Email'=>'E-mail pre upozornenia','The email address where the low AI words notification will be sent.'=>'E-mailová adresa, na ktorú bude odoslané upozornenie na nízky počet AI slov.','Word Threshold'=>'Hranica počtu slov','words'=>'slov','You will be notified when remaining AI words drop below this number.'=>'Dostanete upozornenie, keď počet zostávajúcich AI slov klesne pod toto číslo.','Automatically Translate Slugs'=>'Automaticky prekladať slugy','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Generovať automatické preklady slugov pre príspevky, stránky a vlastné typy obsahu.<br/>Slugy budú automaticky preložené od druhého obnovenia každej stránky.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Táto funkcia je dostupná len v platenj verzii. Inovujte TranslatePress a odomknite ďalšie prémiové funkcie.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Vyžaduje nainštalovaný a aktivovaný <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">doplnok SEO Pack</a>.','Upgrade now'=>'Inovovať teraz','Block Crawlers'=>'Blokovať crawlery','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Zabrániť crawlerom spúšťať automatické preklady na vašom webe.<br>Toto nezabráni crawlerom pristupovať k stránkam tejto lokality.','Limit machine translation / characters per day'=>'Obmedziť automatický preklad / znaky za deň','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Pridajte limit počtu automaticky preložených znakov, aby ste mohli lepšie hospodáriť so svojím projektom.','characters per day'=>'znakov za deň','Today\'s Character Count: '=>'Dnešný počet znakov: ','Log machine translation queries.'=>'Zaznamenávať dotazy strojového prekladu.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Povoliť len na testovacie účely. Môže ovplyvniť výkon.<br>Všetky záznamy sú uložené v databázovej tabuľke wp_trp_machine_translation_log. Na prehliadanie záznamov použite doplnok ako <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> alebo ich prehliadajte priamo vo svojom správcovi databázy (PHPMyAdmin a pod.).','Test API Credentials'=>'Otestovať API poverenia','HTTP Referrer: '=>'HTTP Referrer: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Použite tento HTTP Referrer, ak API umožňuje obmedziť používanie kľúča z jeho ovládacieho panela.','Response'=>'Odpoveď','Response Body'=>'Telo odpovede','Entire Response From wp_remote_get():'=>'Celá odpoveď z wp_remote_get():','All Languages'=>'Všetky jazyky','Select the languages you wish to make your website available in.'=>'Vyberte jazyky, v ktorých chcete sprístupniť svoju webstránku.','Formality'=>'Formálnosť','Code'=>'Kód','Slug'=>'Slug','Default'=>'Predvolené','Formal'=>'Formálne','Informal'=>'Neformálne','Language'=>'Jazyk','This language does not support formality. '=>'Tento jazyk nepodporuje formálnosť. ','Are you sure you want to remove this language?'=>'Naozaj chcete odstrániť tento jazyk?','Custom Languages'=>'Vlastné jazyky','To Add more languages activate the Multiple Languages Addon'=>'Ak chcete pridať ďalšie jazyky, aktivujte doplnok Multiple Languages Addon','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Na pridanie ďalších jazykov potrebujete aktívnu licenciu. Overte vo svojom %1$súčte%2$s, či je vaša licencia platná.','Please %1$senter your license%2$s key first to add more languages.'=>'Najskôr %1$szadajte svoj licenčný kľúč%2$s, ak chcete pridať ďalšie jazyky.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Pridanie viac ako dvoch jazykov je platená funkcia. Upgradujte TranslatePress a odomknite ďalšie prémiové funkcie.','Website Languages'=>'Jazyky webovej stránky','Default Language'=>'Predvolený jazyk','Select the language your content is written in.'=>'Vyberte jazyk, v ktorom je napísaný váš obsah.','WARNING. Changing the default language will invalidate existing translations.'=>'VAROVANIE. Zmena predvoleného jazyka zneplatní existujúce preklady.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Dokonca aj zmena z en_US na en_GB, pretože sú považované za dva rôzne jazyky.','In most cases changing the default flag is all it is needed: '=>'Vo väčšine prípadov stačí zmeniť predvolenú vlajku: ','replace the default flag'=>'nahradiť predvolenú vlajku','Re-run Setup Wizard'=>'Znova spustiť sprievodcu nastavením','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'Sprievodca nastavením vám umožní rýchlo nastaviť TranslatePress. Môžete ho spustiť kedykoľvek.','Language Settings'=>'Nastavenia jazyka','Use Native language name'=>'Použiť natívny názov jazyka','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Začiarknite, ak chcete zobraziť jazyky v ich natívnych názvoch. Inak sa jazyky zobrazia v angličtine.','Use a subdirectory for the default language'=>'Použiť podadresár pre predvolený jazyk','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Začiarknite, ak chcete do URL pridať podadresár pre predvolený jazyk.</br>Začiarknutím tejto možnosti sa predvolený jazyk zobrazený návštevníkom webu stane prvým v zozname „Všetky jazyky“.','Force language in custom links'=>'Vynútiť jazyk vo vlastných odkazoch','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Vyberte Áno, ak chcete vynútiť, aby vlastné odkazy bez jazykového kódovania zachovali aktuálne vybratý jazyk.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'Použite shortcode na akejkoľvek stránke alebo vo widgete.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'Môžete tiež pridať <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> v editore WP Gutenberg.','Menu item'=>'Položka menu','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Prejdite na  %1$sVzhľad -> Menu%2$s a pridajte jazyky do prepínača jazykov v ľubovoľnom menu.','Learn more in our documentation.'=>'Ďalšie informácie nájdete v našej dokumentácii.','Floating language selection'=>'Plávajúci výber jazyka','Add a floating dropdown that follows the user on every page.'=>'Pridajte plávajúci rozbaľovací zoznam, ktorý používateľa sleduje na každej stránke.','Show "Powered by TranslatePress"'=>'Zobraziť "Powered by TranslatePress"','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Zobraziť malý štítok "Powered by TranslatePress" v plávajúcom prepínači jazyka.','5 Days to Better Multilingual Websites'=>'5 dní k lepším viacjazyčným webstránkam','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sPripojte sa k nášmu BEZPLATNÉMU a EXKLUZÍVNEMU kurzu pre nových používateľov%s a zistite, ako zvýšiť svoju viacjazyčnú návštevnosť, osloviť medzinárodné trhy a ušetriť čas aj peniaze, pričom z TranslatePress vyťažíte maximum!','Invalid email address'=>'Neplatná e-mailová adresa','Your email'=>'Váš e-mail','Sign me up!'=>'Prihlásiť ma!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Prihláste sa svojou e-mailovou adresou a získajte 5-dielny e-mailový návod, ktorý vám pomôže naplno využiť možnosti TranslatePress.','Dismiss email course notification'=>'Zavrieť upozornenie na e-mailový kurz','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Ahoj %s,<br>Nezmeškajte dôležitú aktualizáciu – prihláste sa na odber upozornení na bezpečnostné a funkčné aktualizácie a nesenzitívneho diagnostického sledovania.','Allow & Continue'=>'Povoliť a pokračovať','Skip'=>'Preskočiť','This will allow TranslatePress to:'=>'To umožní TranslatePress:','Your profile overview'=>'Prehľad vášho profilu','Name and email address'=>'Meno a e-mailová adresa','Admin Notices'=>'Upozornenia pre správcov','Updates, announcements, marketing, no spam'=>'Aktualizácie, oznámenia, marketing, žiadny spam','Plugin status & settings'=>'Stav a nastavenia doplnku','Active, Deactivated, installed version and settings'=>'Aktívny, deaktivovaný, nainštalovaná verzia a nastavenia','Privacy Policy'=>'Zásady ochrany osobných údajov','Terms of Service'=>'Podmienky používania','Support'=>'Podpora','Documentation'=>'Dokumentácia','Add Extra AI Words'=>'Pridať dodatočné AI slová','Optimize TranslatePress database tables'=>'Optimalizovať databázové tabuľky TranslatePress','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>DÔLEŽITÁ POZNÁMKA:</strong> Pred vykonaním tejto akcie sa dôrazne odporúča najskôr zálohovať databázu.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'DÔLEŽITÉ: Dôrazne sa odporúča najskôr zálohovať databázu!! Ste si istí, že chcete pokračovať?','Operations to perform'=>'Operácie na vykonanie','Remove CDATA for original and dictionary strings'=>'Odstrániť CDATA pre pôvodné a slovníkové reťazce','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Odstraňuje CDATA z tabuliek trp_original_strings a trp_dictionary_*.<br>Tento typ obsahu by nemal byť zachytený doplnkom TranslatePress. Mohol sa v databáze objaviť v starších verziách doplnku.','Remove untranslated links from dictionary tables'=>'Odstrániť nepreložené odkazy zo slovníkových tabuliek','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Odstráni nepreložené odkazy a obrázky zo všetkých tabuliek trp_dictionary_*. Tieto tabuľky obsahujú preklady pre reťazce zadané používateľom, ako je obsah príspevku, názov príspevku, menu atď.','Remove duplicate rows for gettext strings'=>'Odstrániť duplicitné riadky pre gettext reťazce','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Vyčistí všetky tabuľky trp_gettext_* od duplicitných riadkov. Tieto tabuľky obsahujú preklady pre reťazce tém a doplnkov.','Remove duplicate rows for dictionary strings'=>'Odstrániť duplicitné riadky pre slovníkové reťazce','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Vyčistí všetky tabuľky trp_dictionary_* od duplicitných riadkov. Tieto tabuľky obsahujú preklady pre reťazce zadané používateľom, ako je obsah príspevku, názov príspevku, menu atď.','Remove duplicate rows for original dictionary strings'=>'Odstrániť duplicitné riadky pre pôvodné slovníkové reťazce','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Vyčistí tabuľku trp_original_strings od duplicitných riadkov. Táto tabuľka obsahuje reťazce v predvolenom jazyku bez akéhokoľvek prekladu.<br>Tabuľka trp_original_meta, ktorá obsahuje meta informácie odkazujúce na ID rodičovského príspevku, sa tiež regeneruje.<br>Takéto duplicity sa môžu objaviť vo výnimočných situáciách neočakávaného správania.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Nahradiť gettext reťazce, ktoré majú pôvodné ID NULL, správnymi pôvodnými ID','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Opravuje okrajový prípad, keď niektoré gettext reťazce majú nesprávne nastavené pôvodné ID na NULL, čo spôsobuje problémy v prekladovom editore.<br>Táto operácia opraví pôvodné ID v tabuľkách trp_gettext_*.<br>Túto možnosť začiarknite len vtedy, ak ste narazili na problém v prekladovom editore, keď kliknutie na zelenú ceruzku nezobrazilo gettext reťazec na preklad v ľavom bočnom paneli.<br>V opačnom prípade túto možnosť nechajte nezačiarknutú, pretože je to náročná operácia.','Optimize Database'=>'Optimalizovať databázu','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'Aktualizujú sa tabuľky TranslatePress. Ponechajte toto okno otvorené.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'Neaktívne jazyky budú stále viditeľné a aktívne pre správcu. Pre ostatných používateľov nebudú viditeľné v prepínačoch jazykov a nebudú ani prístupné.','unknown'=>'neznáme','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Doplnok Extra Languages</strong> vyžaduje TranslatePress verziu %1$s alebo vyššiu. Momentálne používate verziu %2$s. Ak chcete povoliť túto funkciu, aktualizujte TranslatePress.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Automatické a manuálne zmeny prekladu slugov vykonané, keď bol aktívny <strong>TranslatePress - Multilingual</strong> 2.8.4, museli byť odstránené kvôli niektorým problémom s tou verziou. Všetky preklady slugov z obdobia pred touto verziou sú teraz v používaní. Ďakujeme za pochopenie!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Ak ich naozaj potrebujete, odstránené preklady nájdete v tabuľkách trp_slug_original_obsolete a trp_slug_translation_obsolete.','View Docs'=>'Zobraziť dokumentáciu','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Priradiť každému jazyku inú doménu alebo subdoménu. Keď návštevníci pristupujú k týmto doménam, TranslatePress priamo načíta príslušný jazykový preklad bez presmerovania.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Príklad: %1$s pre angličtinu, %2$s pre španielčinu, %3$s pre francúzštinu.','Before enabling:'=>'Pred povolením:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Uistite sa, že vaše domény sú zaregistrované, nasmerované na váš server a majú nakonfigurované SSL certifikáty.','Domain'=>'Doména','Map this language to a different domain or sub-domain.'=>'Priradiť tento jazyk k inej doméne alebo subdoméne.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Predvyplniť aktuálnou doménou','Check DNS'=>'Skontrolovať DNS','Checking DNS...'=>'Kontroluje sa DNS...','DNS is correctly configured!'=>'DNS je správne nakonfigurované!','DNS check failed. Please verify your domain configuration.'=>'Kontrola DNS zlyhala. Overte prosím konfiguráciu vašej domény.','This domain is already assigned to another language.'=>'Táto doména je už priradená k inému jazyku.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Doplnok Different Domain per Language</strong> vyžaduje TranslatePress vo verzii %1$s alebo vyššej. Momentálne používate verziu %2$s. Ak chcete povoliť túto funkciu, aktualizujte prosím TranslatePress.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Poznámka: Táto možnosť je zakázaná, keď je aktívny doplnok Different Domain for Language.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Different Domain per Language: Doména je povinná, keď je povolené mapovanie domén. Prepínač bol zakázaný pre jazyky s práznymi doménami.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Different Domain per Language: Rovnaká doména nemôže byť priradená viacerým jazykom. Prepínač bol zakázaný pre duplicitné domény.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Different Domain per Language: Doména jazyka nemôže byť rovnaká ako hlavná URL stránky. Prepínač bol zakázaný pre zhodujúcu sa doménu.','Please enter a domain.'=>'Zadajte prosím doménu.','Invalid domain format.'=>'Neplatný formát domény.','Could not reach domain: %s'=>'K doméne sa nepodarilo pripojiť: %s','Domain returned HTTP status %d.'=>'Doména vrátila stav HTTP %d.','Domain is reachable!'=>'Doména je dostupná!','Limit this menu item to the following languages'=>'Obmedziť túto položku menu na nasledujúce jazyky','Date format'=>'Formát dátumu','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Prispôsobte formátovanie dátumu pre každý preložený jazyk.<br/>Nechajte prázdne pre predvolené nastavenie WP alebo viac informácií nájdete <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">tu</a>','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'Ak chcete upraviť existujúci jazyk TranslatePress, zadajte kód jazyka a vyplňte len stĺpce, ktoré chcete prepísať (napr. názov jazyka, vlajka).<br>Môžete tiež pridať nové vlastné jazyky. Budú dostupné v časti Všeobecné nastavenia, v zozname Všetky jazyky, kde je možné upraviť URL slug.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'Pre vlastnú vlajku najprv nahrajte obrázok do knižnice médií a potom vložte URL.<br>Zmena alebo odstránenie vlastného jazyka ovplyvní preklady a URL stránky.<br>Kód jazyka a ISO kód by mali obsahovať len písmená, číslice, "-" a "_".<br>ISO kódy nájdete na <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO kódy</a> a <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL cieľové kódy</a>.','Language code'=>'Kód jazyka','Language name'=>'Názov jazyka','Native name'=>'Natívny názov','ISO Code'=>'ISO kód','Flag URL'=>'URL vlajky','Text RTL'=>'RTL text','Custom language'=>'Vlastný jazyk','Disable dynamic translation'=>'Zakázať dynamický preklad','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Zakáže detekciu reťazcov zobrazovaných dynamicky pomocou JavaScriptu. <br/>Reťazce načítané prostredníctvom volania AJAX na strane servera sa stále preložia.','Disable translation for gettext strings'=>'Zakázať preklad pre gettext reťazce','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Reťazce Gettext sú reťazce vypisované témami a pluginmi. <br> Preklad týchto typov reťazcov prostredníctvom TranslatePress môže byť zbytočný, ak sú už preložené pomocou prekladového systému súborov .po/.mo.<br>Povolenie tejto možnosti môže v určitých prípadoch zlepšiť výkon načítavania stránky vášho webu. Nevýhodou je, že už nemôžete upravovať preklady Gettext pomocou TranslatePress ani využívať automatický preklad týchto reťazcov.','Gettext Strings translation is disabled'=>'Preklad reťazcov Gettext je zakázaný','To enable it go to '=>'Ak ho chcete povoliť, prejdite na ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Rozšírené nastavenia->Ladenie->Zakázať preklad reťazcov Gettext',' and uncheck the Checkbox.'=>' a zrušte začiarknutie políčka.','Dismiss'=>'Zavrieť','Exclude translated links from sitemap'=>'Vylúčiť preložené odkazy zo sitemap','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'Nezahŕňať preložené odkazy do sitemaps generovaných SEO pluginmi.<br/>Vyžaduje nainštalovaný a aktivovaný <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> doplnok SEO Pack</a>.','Disable post container tags for post title'=>'Zakázať kontajnerové značky príspevku pre názov príspevku','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Zakáže indexovanie názvu príspevku vo vyhľadávaní v preložených jazykoch.<br/>Užitočné, keď názov príspevku neumožňuje HTML a tým rozbíja stránku.','Disable post container tags for post content'=>'Zakázať kontajnerové značky príspevku pre obsah príspevku','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Zakáže indexovanie obsahu príspevku vo vyhľadávaní v preložených jazykoch.<br/>Užitočné, keď obsah príspevku neumožňuje HTML a tým rozbíja stránku.','Do not translate certain paths'=>'Neprekladať určité cesty','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Vyberte, ktoré cesty je možné prekladať. Podporuje žolík na konci cesty.<br>Napríklad, ak chcete vylúčiť https://example.com/some/path, môžete použiť pravidlo /some/path/ alebo /some/*.<br>Zadajte každé pravidlo na samostatný riadok. Na vylúčenie domovskej stránky použite {home}.','Exclude Paths From Translation'=>'Vylúčiť cesty z prekladu','Translate Only Certain Paths'=>'Prekladať iba určité cesty','Enable the hreflang x-default tag for language:'=>'Povoliť značku hreflang x-default pre jazyk:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Povolí hreflang="x-default" pre celý jazyk. Podrobnosti nájdete v dokumentácii.','Translate numbers and numerals'=>'Prekladať čísla a číslice','Enable translation of numbers ( e.g. phone numbers)'=>'Povoliť preklad čísel (napr. telefónnych čísel)','Selector'=>'Selektor','Exclude from dynamic translation'=>'Vylúčiť z dynamického prekladu','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'Dynamicky neprekladať reťazce, ktoré sa nachádzajú v HTML uzloch zodpovedajúcich týmto selektorom.<br>Vylučuje všetkých potomkov HTML uzlov zodpovedajúcich týmto selektorov z prekladu pomocou JavaScriptu.<br/>Tieto reťazce sa stále preložia na strane servera, ak je to možné.','Gettext String'=>'Reťazec Gettext','Exclude Gettext Strings'=>'Vylúčiť reťazce Gettext','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Vylúčiť tieto reťazce z prekladu ako reťazce Gettext pomocou TranslatePress. Ak chcete zohľadniť akýkoľvek reťazec Gettext, nechajte doménu prázdnu.<br/>Stále je možné ich preložiť prostredníctvom súborov po/mo.','Exclude selectors only from automatic translation'=>'Vylúčiť selektory iba z automatického prekladu','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'Automaticky neprekladať reťazce, ktoré sa nachádzajú v HTML uzloch zodpovedajúcich týmto selektorom.<br>Vylučuje všetkých potomkov HTML uzlov zodpovedajúcich týmto selektorov z automatického prekladu.<br>Ručný preklad týchto reťazcov je stále možný.','Exclude selectors from translation'=>'Vylúčiť selektory z prekladu','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'Neprekladať reťazce, ktoré sa nachádzajú v HTML uzloch zodpovedajúcich týmto selektorom.<br>Vylučuje všetkých potomkov HTML uzlov zodpovedajúcich týmto selektorov z prekladu.<br>Tieto reťazce nemožno preložiť ručne ani automaticky.','String'=>'Reťazec','Exclude strings from automatic translation'=>'Vylúčiť reťazce z automatického prekladu','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'Tieto reťazce neprekladať automaticky (napr. názvy, technické výrazy...)<br>Odseky obsahujúce tieto reťazce sa stále preložia okrem určenej časti.','Fix broken HTML'=>'Opraviť poškodené HTML','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Všeobecný pokus o opravu poškodeného alebo chýbajúceho HTML na preložených stránkach.<br/>','Force slash at end of home url:'=>'Vynútiť lomku na konci home url:','Ads a slash at the end of the home_url() function'=>'Pridá lomku na koniec funkcie home_url()','Show Both (recommended)'=>'Zobraziť obe (odporúčané)','Remove Country Locale'=>'Odstrániť krajinný lokál','Remove Region Independent Locale'=>'Odstrániť lokál nezávislý od regiónu','Remove duplicate hreflang'=>'Odstrániť duplicitné hreflang','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Vyberte, ktoré hreflang značky sa zobrazia na vašom webe.<br/>Odporúčame zobrazovať oba typy hreflang značiek, ako uvádza <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">dokumentácia Google</a>.<br/>Odstránenie krajinnej lokalizácie v prípade viacerých krajinných lokalizácií rovnakého jazyka (napr. angličtina UK a angličtina US) spôsobí zobrazenie jednej hreflang značky s odkazom len na jednu z regionálnych lokalizácií tohto jazyka.','Default (example: en-US, fr-CA, etc.)'=>'Predvolené (príklad: en-US, fr-CA atď.)','Regional (example: en, fr, es, etc.)'=>'Regionálny (príklad: en, fr, es atď.)','HTML Lang Attribute Format'=>'Formát atribútu HTML Lang','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Zmeňte atribút lang značky html na formát, ktorý zahŕňa aj kód krajiny alebo nie. <br>V HTML by sa atribút lang (<html lang="en-US">) mal používať na špecifikáciu jazyka textového obsahu, aby prehliadač mohol správne zobraziť alebo spracovať váš obsah (napr. pri delení slov, štýlovaní, kontrole pravopisu atď.).','Load legacy Language Switcher'=>'Načítať starý prepínač jazykov','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'Vzťahuje sa na všetky typy prepínačov jazykov (plávajúci, shortcode a menu). Po povolení sa stránka vráti k používaniu pôvodného prepínača jazykov nastaveného na karte Všeobecné nastavenia a nahradí novú prispôsobiteľnú verziu. Vaše existujúce nastavenia prepínača zostanú uložené, ale budú ignorované, kým je táto možnosť aktívna.','Load legacy SEO Pack Add-On'=>'Načítať starý doplnok SEO Pack','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'Ak nedávna migrácia na nový prepis slugov spôsobuje problémy, nastavte to na Áno, aby ste použili starú metódu <br> Prosím, <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">otvorte podporný tiket</a> a dajte nám vedieť o problémoch, ktoré máte.','Manual Translation Only'=>'Iba manuálny preklad','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress proaktívne skenuje a ukladá reťazce do databázy, keď používatelia pristupujú k preloženým stránkam. <br>Toto nastavenie zakazuje túto funkciu a umožňuje preklad a ukladanie reťazcov len vo vnútri Prekladového editora. <br>Tiež zakazuje strojový preklad mimo Prekladového editora, čím vám dáva lepšiu kontrolu nad spotrebou znakov, pretože prekladá len stránky, ktoré navštívite v Prekladovom editore.','Open language switcher only on click'=>'Otvoriť prepínač jazykov len kliknutím','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Otvorte prepínač jazykov shortcode kliknutím namiesto prejdenia myšou.<br> Zatvorte ho kliknutím naň, kliknutím kamkoľvek inde na obrazovku alebo stlačením klávesu Escape. Toto sa týka len prepínača jazykov shortcode.','Show opposite language in the language switcher'=>'Zobraziť opačný jazyk v prepínači jazykov','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Premení prepínač jazykov na tlačidlo zobrazujúce druhý dostupný jazyk, nie aktuálny.<br> Funguje len vtedy, keď sú práve dva jazyky – predvolený a prekladový.<br>Toto ovplyvní tiež prepínač jazykov shortcode a plávajúci prepínač jazykov.<br> Ak to chcete dosiahnuť v prepínači jazykov v menu, prejdite na Vzhľad->Menu->Prepínač jazykov a vyberte Opačný jazyk.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Kliknite sem</a> pre prístup k nástroju na optimalizáciu databázy.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Pomáha odstrániť možné duplicitné preklady, vyčistiť nepotrebné údaje a opraviť možné problémy s metadátami.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Tu</a> si môžete pozrieť posledných 5 chýb SQL súvisiacich s TranslatePress, ak existujú.','Troubleshooting'=>'Riešenie problémov','Exclude Gettext strings'=>'Vylúčiť reťazce Gettext','Debug'=>'Ladenie','Custom languages'=>'Vlastné jazyky','Miscellaneous options'=>'Rôzne možnosti','Exclude strings & pages'=>'Vylúčiť reťazce a stránky','Automatic Translation Memory'=>'Automatická prekladová pamäť','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Použiť rovnaký preklad pre podobný text. Reťazce musia mať podobnosť 95 %.<br>Pomáha zabrániť strate existujúceho prekladu pri oprave preklepov alebo pri drobných úpravách pôvodného textu. <br>Ak už preklad pre veľmi podobný pôvodný reťazec existuje, automaticky sa použije pre aktuálny pôvodný reťazec.<br>Neplatí pri úpravách textu, ktorý je súčasťou prekladového bloku, pokiaľ nie je nový text znova ručne zlúčený v prekladovom bloku.<br>Každý reťazec musí mať minimálne 50 znakov.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'VAROVANIE: Táto funkcia môže negatívne ovplyvniť časy načítavania stránok v sekundárnych jazykoch, najmä pri veľkých databázach (napríklad webové stránky s veľkým počtom stránok alebo produktov). Ak zaznamenáte pomalé načítavanie, vypnite túto funkciu a skúste to znova.','Fix missing dynamic content'=>'Opraviť chýbajúci dynamický obsah','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Môže pomôcť opraviť chýbajúci obsah vložený pomocou JavaScriptu. <br> Na krátky okamih zobrazuje dynamicky vložený obsah v pôvodnom jazyku pred dokončením požiadavky na preklad.','Filter Gettext wrapping from post content and title'=>'Filtrovať obal Gettext z obsahu a názvu príspevku','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtrovať obal Gettext, ako napríklad #!trpst#trp-gettext, z aktualizovaného obsahu a názvu príspevku. Neovplyvňuje predchádzajúci obsah príspevku. <br/><strong>Pred zapnutím sa odporúča zálohovať databázu.</strong>','Filter Gettext wrapping from post meta'=>'Filtrovať obal Gettext z metadát príspevku','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtrovať obal Gettext, ako napríklad #!trpst#trp-gettext, zo všetkých aktualizovaných metadát príspevku. Neovplyvňuje predchádzajúce metadáta príspevku. <br/><strong>Pred zapnutím sa odporúča zálohovať databázu.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Kľúč API Google Translate','Add your API Key here...'=>'Sem pridajte svoj kľúč API...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Navštívte <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">tento odkaz</a>, kde zistíte, ako nastaviť API kľúč, <strong>kontrolovať náklady na API</strong> a nastaviť obmedzenia HTTP referrera.','Your HTTP referrer is: %s'=>'Váš HTTP referrer je: %s','There was an error on the server processing your Google Translate key.'=>'Na serveri sa vyskytla chyba pri spracovaní vášho kľúča Google Translate.','There was an error with your Google Translate key.'=>'Vyskytla sa chyba s vaším kľúčom Google Translate.','Please check your TranslatePress license key.'=>'Skontrolujte prosím svoj licenčný kľúč TranslatePress.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'Pre túto webovú stránku nebola zistená žiadna aktívna licencia.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'Ak chcete povoliť automatický preklad pomocou TranslatePress AI, potrebujete licenčný kľúč, ktorý získate vytvorením bezplatného účtu.','Create your Free Account'=>'Vytvorte si bezplatný účet',' or '=>' alebo ','Enter your license key'=>'Zadajte svoj licenčný kľúč',' Or %1$spurchase one here%2$s'=>' Alebo %1$szakúpte si ho tu%2$s','Your free account includes: '=>'Váš bezplatný účet zahŕňa: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Získajte viac AI slov a odomknite všetky AI funkcie pomocou TranslatePress Pro.','You have a valid %s <strong>license</strong>.'=>'Máte platnú %s <strong>licenciu</strong>.',' words remaining. '=>' zostávajúcich slov. ','Recheck'=>'Znova skontrolovať','Rechecking...'=>'Kontroluje sa...','Done.'=>'Hotovo.','Manage your license & quota on the %s'=>'Spravujte svoju licenciu a kvótu na %s','TranslatePress.com Account Page'=>'Stránka účtu TranslatePress.com','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'Podpora SEO pre slug stránky, názov stránky, popis a informácie sociálneho grafu Facebooku a Twitteru. Atribút lang HTML je správne nastavený.','Enable Modules'=>'Povoliť moduly','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'Povoľte doplnkové moduly na rozšírenie TranslatePress a vylepšenie funkcionality vášho preloženého webu.','More functionality with TranslatePress Pro.'=>'Viac funkcionality s TranslatePress Pro.','Already a Pro User?'=>'Už ste používateľom Pro?','Activate License Key'=>'Aktivovať licenčný kľúč','This add-on is not available on your current plan.'=>'Tento doplnok nie je dostupný vo vašom aktuálnom pláne.','Continue'=>'Pokračovať','The link you followed has expired. Please reload the page and try again.'=>'Odkaz, ktorý ste sledovali, vypršal. Znova načítajte stránku a skúste to znova.','A valid license is required to enable Automatic Translation.'=>'Na aktiváciu automatického prekladu je potrebná platná licencia.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'Váš licenčný kľúč je pre túto URL deaktivovaný. Znova ho aktivujte na <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Správa stránok.','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Nezhoda licenčného kľúča.</strong> Zadaná licencia nezodpovedá nainštalovanej verzii TranslatePress.</p><p>Skontrolujte, či ste zo svojho účtu TranslatePress nainštalovali správnu verziu pre vašu licenciu.</p>','Automatically translate your website using TranslatePress AI.'=>'Automaticky preložte svoju webovú stránku pomocou TranslatePress AI.','In order to enable Automatic Translation using TranslatePress AI, please enter your license key from'=>'Ak chcete aktivovať automatický preklad pomocou TranslatePress AI, zadajte svoj licenčný kľúč z','your account.'=>'vášho účtu.','Skip and continue with manual translation »'=>'Preskočiť a pokračovať v manuálnom preklade »','Get Your Free TranslatePress AI License'=>'Získajte svoju bezplatnú licenciu TranslatePress AI','Generate License'=>'Vygenerovať licenciu','Creating a free account includes: '=>'Vytvorenie bezplatného účtu zahŕňa: ','Are you a TranslatePress PRO user?'=>'Ste používateľom TranslatePress PRO?','Install & Activate your pro plugin.'=>'Nainštalujte a aktivujte svoj profesionálny doplnok.','Skip this step'=>'Preskočiť tento krok','The email address you added is incorrect.'=>'E-mailová adresa, ktorú ste pridali, je nesprávna.','Setup Complete'=>'Nastavenie dokončené','You\'re ready to start translating!'=>'Ste pripravení začať prekladať!','You have successfully set up TranslatePress for your website.'=>'Úspešne ste nastavili TranslatePress pre svoju webovú stránku.','Receive '=>'Získajte ','Yes, send me multilingual growth tips.'=>'Áno, posielajte mi tipy na multijazyčný rast.','Start translating'=>'Začať prekladať','Sign Up and Start translating'=>'Zaregistrujte sa a začnite prekladať','Please upload a TranslatePress Pro plugin file.'=>'Nahrajte súbor pluginu TranslatePress Pro.','Upload error: '=>'Chyba pri nahrávaní: ','Install failed: '=>'Inštalácia zlyhala: ','Plugin installed, but entry file not found. '=>'Plugin bol nainštalovaný, ale vstupný súbor nebol nájdený. ','Activation error: '=>'Chyba aktivácie: ','Invalid plugin specified.'=>'Zadaný neplatný plugin.','Invalid action specified.'=>'Zadaná neplatná akcia.','Plugin deactivation failed.'=>'Deaktivácia pluginu zlyhala.','Plugin activation failed: '=>'Aktivácia pluginu zlyhala: ','First, install and activate TranslatePress Pro'=>'Najprv nainštalujte a aktivujte TranslatePress Pro','Please upload the TranslatePress PRO zip archive from your'=>'Nahrajte zip archív TranslatePress PRO z vášho','TranslatePress Account'=>'TranslatePress Account','Install and Activate'=>'Nainštalovať a aktivovať','Installed Pro versions'=>'Nainštalované Pro verzie','« Go back'=>'« Späť','Activate License »'=>'Aktivovať licenciu »','You are trying to add an invalid additional language. Please select a valid option.'=>'Pokúšate sa pridať neplatný dodatočný jazyk. Vyberte platnú možnosť.','Please add an additional language.'=>'Pridajte ďalší jazyk.','You are trying to add an invalid default language. Please select a valid option.'=>'Pokúšate sa pridať neplatný predvolený jazyk. Vyberte platnú možnosť.','You need to select a default language.'=>'Musíte vybrať predvolený jazyk.','Configure Site Languages'=>'Nastaviť jazyky webu','Select the default and additional languages for your website.'=>'Vyberte predvolený a ďalšie jazyky pre váš web.','You can edit your site languages at any point.'=>'Jazyky webu môžete upraviť kedykoľvek.','Additional Language'=>'Ďalší jazyk','Choose a secondary language...'=>'Vyberte sekundárny jazyk...','Add Language'=>'Pridať jazyk','Choose a language...'=>'Vyberte jazyk...','Add more than two languages with TranslatePress Pro.'=>'Pridajte viac ako dva jazyky pomocou TranslatePress Pro.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Manage Sites.'=>'Váš licenčný kľúč je pre túto URL deaktivovaný. Znova ho aktivujte na adrese <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Spravovať stránky.','Add your License Key'=>'Pridajte svoj licenčný kľúč','Add your License Key to unlock all premium features. Find the License Key in your'=>'Pridajte svoj licenčný kľúč, aby ste odomkli všetky prémiové funkcie. Licenčný kľúč nájdete vo svojom','Your license is valid and active.'=>'Vaša licencia je platná a aktívna.','« Go Back'=>'« Späť','Set up Language Switcher'=>'Nastaviť prepínač jazykov','Select the style of the language switcher. You will find more ways to display it, in plugin settings.'=>'Vyberte štýl prepínača jazykov. Ďalšie spôsoby zobrazenia nájdete v nastaveniach doplnku.','Displays a small language drop-down across your website, in a corner of your choosing.'=>'Zobrazí malý rozbaľovací zoznam jazykov na vašom webe v rohu podľa vášho výberu.','Switcher Location'=>'Umiestnenie prepínača','Apply a Template'=>'Použiť šablónu','You can customize the design later'=>'Dizajn môžete prispôsobiť neskôr','Default Template'=>'Predvolená šablóna','Dark Template'=>'Tmavá šablóna','Border Template'=>'Šablóna s okrajom','Border'=>'Okraj','Transparent Template'=>'Priehľadná šablóna','Transparent'=>'Priehľadná','Welcome to TranslatePress'=>'Vitajte v TranslatePress','Quick guided setup to configure TranslatePress in no time!'=>'Rýchle navádzané nastavenie na konfiguráciu TranslatePress v okamihu!','It takes less than a minute.'=>'Zaberie to menej ako minútu.','Scanning item %1$d of %2$d...'=>'Skenovanie položky %1$d z %2$d...','Manually translated'=>'Ručne preložené','Automatically translated'=>'Automaticky preložené','Not translated'=>'Nepreložené','Bulk Actions'=>'Hromadné akcie','Delete entries'=>'Odstrániť položky','Edit'=>'Upraviť','Delete'=>'Odstrániť','Filter'=>'Filtrovať','Clear filters'=>'Vymazať filtre','Add New'=>'Pridať nový','Rescan plugins and theme for strings'=>'Znova preskenovať pluginy a tému na reťazce','Scanning plugins and theme for strings...'=>'Prebieha skenovanie pluginov a témy na reťazce...','Plugins and theme scan is complete'=>'Skenovanie pluginov a témy je dokončené','Plugins and theme scan did not finish due to an error'=>'Skenovanie pluginov a témy sa nedokončilo kvôli chybe','Import / Export'=>'Import / Export','items'=>'položky','See More'=>'Zobraziť viac','See Less'=>'Zobraziť menej','Apply'=>'Použiť','No strings match your query.'=>'Žiadne reťazce nezodpovedajú vášmu dopytu.','Try to rescan plugins and theme for strings.'=>'Skúste znova preskenovať pluginy a tému na reťazce.','An error occurred while loading results. Most likely you were logged out. Reload page?'=>'Pri načítavaní výsledkov nastala chyba. Pravdepodobne ste boli odhlásení. Znova načítať stránku?','found in translation'=>'nájdené v preklade','Select All'=>'Vybrať všetko','Select Visible'=>'Vybrať viditeľné','You are about to perform this action on all the strings matching your filter, not just the visibly checked. To perform the action only to the visible strings click "Select Visible" from the table header dropdown.'=>'Chystáte sa vykonať túto akciu na všetky reťazce zodpovedajúce vášmu filtru, nielen na viditeľne zaškrtnuté. Ak chcete vykonať akciu len na viditeľné reťazce, kliknite vo rozbaľovacej ponuke hlavičky tabuľky na "Vybrať viditeľné".','You are about to perform this action only on the visible strings. To perform the action on all the strings matching the filter click "Select All" from the table header dropdown.'=>'Chystáte sa vykonať túto akciu len na viditeľné reťazce. Ak chcete vykonať akciu na všetky reťazce zodpovedajúce filtru, kliknite vo rozbaľovacej ponuke hlavičky tabuľky na "Vybrať všetky".','To continue please type the word:'=>'Ak chcete pokračovať, zadajte slovo:','The word typed was incorrect. Action was cancelled.'=>'Zadané slovo bolo nesprávne. Akcia bola zrušená.','Warning: This action cannot be undone. Deleting a string will remove its current translation. The original string will appear again in this interface after TranslatePress detects it. This action is NOT equivalent to excluding the string from being translated again.'=>'Upozornenie: Túto akciu nie je možné vrátiť späť. Odstránenie reťazca odstráni jeho aktuálny preklad. Pôvodný reťazec sa v tomto rozhraní znova zobrazí, keď ho TranslatePress zistí. Táto akcia NIE JE ekvivalentná vylúčeniu reťazca z prekladania.','%d original entries and their translations were deleted.'=>'Bolo odstránených %d pôvodných záznamov a ich prekladov.','Navigate to next page'=>'Prejsť na ďalšiu stranu','Navigate to previous page'=>'Prejsť na predchádzajúcu stranu','Navigate to first page'=>'Prejsť na prvú stranu','Navigate to last page'=>'Prejsť na poslednú stranu','Type a page number to navigate to'=>'Zadajte číslo strany, na ktorú chcete prejsť','Incorrect page number. Type a page number between 1 and total number of pages'=>'Nesprávne číslo strany. Zadajte číslo strany medzi 1 a celkovým počtom strán.','Search original and translated strings containing typed keywords while also matching selected filters. Place string in quotes for exact match: "string"'=>'Hľadať pôvodné a preložené reťazce obsahujúce napísané kľúčové slová a zároveň zodpovedajúce vybraným filtrom. Pre presnú zhodu vložte reťazec do úvodzoviek: "reťazec"','Filter strings according to selected translation status, filters and keywords and selected filters'=>'Filtrovať reťazce podľa vybraného stavu prekladu, filtrov a kľúčových slov a vybraných filtrov','Removes selected filters'=>'Odstráni vybraté filtre','See options for selecting all strings'=>'Zobraziť možnosti pre výber všetkých reťazcov','Click to sort strings by this column'=>'Kliknite na zoradenie reťazcov podľa tohto stĺpca','Language in which the translation status filter applies. Leave unselected for the translation status to apply to ANY language'=>'Jazyk, na ktorý sa vzťahuje filter stavu prekladu. Ponechajte nevybraté, aby sa stav prekladu vzťahoval na akýkoľvek jazyk.','Search'=>'Hľadať','Slugs that are not found in either one of the other categories.'=>'Slugs, ktoré sa nenachádzajú v žiadnej z ostatných kategórií.','Plugins and Theme String Translation'=>'Preklad reťazcov pluginov a témy','Gettext'=>'Gettext','Search Gettext Strings'=>'Hľadať reťazce Gettext','ID'=>'ID','Original String'=>'Pôvodný reťazec','Translation'=>'Preklad','Filter by domain'=>'Filtrovať podľa domény','Filter by type'=>'Filtrovať podľa typu','Email text'=>'Text e-mailu','Emails String Translation'=>'Preklad e-mailových reťazcov','Emails'=>'E-maily','Search Email Strings'=>'Hľadať e-mailové reťazce','User Inputted String Translation'=>'Preklad reťazcov zadaných používateľom','Regular'=>'Bežné','Search Regular Strings'=>'Hľadať bežné reťazce','Filter by Translation Block'=>'Filtrovať podľa bloku prekladu','URL Slugs Translation'=>'Preklad URL slugov','String Translation Editor'=>'Editor prekladu reťazcov','TranslatePress has detected and cleaned up some failed translation entries in your database following %1$san isolated incident%2$s. No further action is required.'=>'TranslatePress zaznamenal a vyčistil vo vašej databáze niektoré chybné prekladové záznamy vzniknuté po %1$sizolovanom incidente%2$s. Nie je potrebná žiadna ďalšia akcia.','Post Slug'=>'Slug príspevku','Invalid language code'=>'Neplatný kód jazyka','First by browser language, then IP address (recommended)'=>'Najprv podľa jazyka prehliadača, potom podľa IP adresy (odporúčané)','First by IP address, then by browser language'=>'Najprv podľa IP adresy, potom podľa jazyka prehliadača','Only by browser language'=>'Len podľa jazyka prehliadača','Only by IP address'=>'Len podľa IP adresy','A popup appears asking the user if they want to be redirected'=>'Zobrazí sa vyskakovacie okno s otázkou, či sa používateľ chce presmerovať','Redirect directly (*not recommended)'=>'Presmerovať priamo (*neodporúča sa)','Pop-up window over the content'=>'Vyskakovacie okno nad obsahom','Hello bar before the content'=>'Panel s oznámením pred obsahom','WARNING. Cannot determine your language preference based on your current IP.<br>This is most likely because the website is on a local environment.'=>'VAROVANIE. Na základe vašej aktuálnej IP adresy nie je možné určiť preferenciu jazyka.<br>Pravdepodobne je to preto, že webová stránka je v lokálnom prostredí.','Go to <a href="%s" target="_self">Advanced</a> tab to change this feature\'s settings'=>'Prejdite na <a href="%s" target="_self">Rozšírené</a> záložku, ak chcete zmeniť nastavenia tejto funkcie','User Language Detection Method'=>'Metóda zisťovania jazyka používateľa','Select how the language should be detected for first time visitors.<br>The visitor\'s last displayed language will be remembered through cookies.'=>'Vyberte, ako sa má zisťovať jazyk pri prvej návšteve.<br>Posledný zobrazený jazyk návštevníka sa zapamätá prostredníctvom cookies.','User Notification Popup'=>'Vyskakovacie okno s upozornením pre používateľa','A popup appears asking the user if they want to be redirected.'=>'Zobrazí sa vyskakovacie okno s otázkou, či sa používateľ chce presmerovať.','Popup Type'=>'Typ vyskakovacieho okna','Popup Text'=>'Text vyskakovacieho okna','The same text is displayed in all languages. <br>A selecting language switcher will be appended to the pop-up. The detected language is pre-selected.'=>'Rovnaký text sa zobrazuje vo všetkých jazykoch. <br>K vyskakovaciemu oknu sa pripojí prepínač jazykov s výberom. Rozpoznaný jazyk je predvolený.','Button Text'=>'Text tlačidla','Write the text you wish to appear on the button..'=>'Napíšte text, ktorý chcete zobraziť na tlačidle..','Close Button Text'=>'Text tlačidla na zatvorenie','Write the text you wish to appear on the close button. Leave empty for just the close button.'=>'Napíšte text, ktorý chcete zobraziť na tlačidle na zatvorenie. Nechajte prázdne, ak má byť len zatváracie tlačidlo.','Bad request. There was an error accessing the DeepL API.'=>'Nesprávna požiadavka. Pri prístupe k DeepL API došlo k chybe.','The API key entered is invalid.'=>'Zadaný API kľúč je neplatný.','The API resource could not be found.'=>'Zdroj API sa nepodarilo nájsť.','The request size is too large.'=>'Veľkosť požiadavky je príliš veľká.','The request is too long.'=>'Požiadavka je príliš dlhá.','Too many requests. Please try again later.'=>'Príliš veľa požiadaviek. Skúste to znova neskôr.','Your translation quota has been reached.'=>'Dosiahli ste svoj prekladový limit.','We could not process your request. Please try again later.'=>'Vašu požiadavku sa nepodarilo spracovať. Skúste to znova neskôr.','There is an error on the DeepL service and your request could not be processed.'=>'V službe DeepL došlo k chybe a vašu požiadavku sa nepodarilo spracovať.','DeepL API Type'=>'Typ DeepL API','Pro'=>'Bezplatný','Free'=>'Pro','Select the type of DeepL API you want to use.'=>'Vyberte typ DeepL API, ktorý chcete používať.','DeepL API Key'=>'Kľúč DeepL API','Visit <a href="%s" target="_blank">this link</a> to see how you can set up an API key and control API costs.'=>'Navštívte <a href="%s" target="_blank">tento odkaz</a>, ak chcete vedieť, ako nastaviť API kľúč a kontrolovať náklady na API.','Translator'=>'Prekladateľ',' TranslatePress Settings'=>' Nastavenia TranslatePress','Allow this user to translate the website.'=>'Povoliť tomuto používateľovi prekladať webstránku.','(inactive)'=>'(neaktívny)','Taxonomy Slugs'=>'Slugy taxonómie','Search Taxonomy Slugs'=>'Hľadať slugy taxonómie','Taxonomy Slug'=>'Slug taxonómie','Term Slugs'=>'Slugy výrazov','Search Term Slugs'=>'Hľadať slugy výrazov','Term Slug'=>'Slug výrazu','Taxonomy'=>'Taxonómia','Filter by Taxonomy'=>'Filtrovať podľa taxonómie','Post Slugs'=>'Slugy príspevkov','Search Post Slugs'=>'Hľadať slugy príspevkov','Post ID'=>'ID príspevku','Post Type'=>'Typ príspevku','Filter by Post Type'=>'Filtrovať podľa typu príspevku','Published'=>'Zverejnené','Any Post Status'=>'Akýkoľvek stav príspevku','Post Type Base Slugs'=>'Základné slugy typov príspevkov','Post Type Base Slug'=>'Základný slug typu príspevku','Search Post Type Base Slugs'=>'Hľadať základné slugy typov príspevkov','WooCommerce Slugs'=>'Slugy WooCommerce','WooCommerce Slug'=>'Slug WooCommerce','Search WooCommerce Slugs'=>'Hľadať slugy WooCommerce','Other Slugs'=>'Ostatné slugy','Search Other Slugs'=>'Hľadať ostatné slugy','Verbiage for the DeepL Pro Add-onTranslatePress Pro Add-on'=>'TranslatePress Pro Add-on','Verbiage for the DeepL Pro Add-onAddons tab'=>'Záložka doplnkov','page 1 of 3of'=>'/','Untranslated in this languagein'=>'v']];